# Define LCS for strings
def longest_common_substring_length(a, b):
    # dynamic programming O(n*m)
    m = len(a)
    n = len(b)
    # if too long, maybe speed? but strings are short
    dp = [[0]*(n+1) for _ in range(m+1)]
    lcs = 0
    for i in range(m):
        for j in range(n):
            if a[i] == b[j]:
                dp[i+1][j+1] = dp[i][j] + 1
                if dp[i+1][j+1] > lcs:
                    lcs = dp[i+1][j+1]
    return lcs

def token_f1(a,b):
    a_tokens = a.split()
    b_tokens = b.split()
    if not a_tokens or not b_tokens:
        return 0.0
    a_set = {}
    for t in a_tokens:
        a_set[t] = a_set.get(t,0) + 1
    b_set = {}
    for t in b_tokens:
        b_set[t] = b_set.get(t,0) + 1
    common = 0
    for t, cnt in a_set.items():
        common += min(cnt, b_set.get(t,0))
    precision = common / len(b_tokens)
    recall = common / len(a_tokens)
    if precision + recall == 0:
        return 0.0
    return 2*precision*recall/(precision+recall)

